function afficherPanneau(config) {
  const conteneur = document.querySelector(config.selector);
  if (!conteneur) return;
  conteneur.textContent = config.message;
  conteneur.classList.remove('info', 'success', 'error');
  conteneur.classList.add(config.type);
  conteneur.setAttribute('data-message-id', config.dataId);
}
